    17Ôćĺfunc Auth(store KeyStore) Middleware {
    18Ôćĺ	return func(next http.Handler) http.Handler {
    19Ôćĺ		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    20Ôćĺ			header := r.Header.Get("Authorization")
    21Ôćĺ			if !strings.HasPrefix(header, "Bearer ") {
    22Ôćĺ				RespondError(w, r, http.StatusUnauthorized, "unauthorized", "Missing API key")
    23Ôćĺ				return
    24Ôćĺ			}
    25Ôćĺ			rawKey := strings.TrimPrefix(header, "Bearer ")
    26Ôćĺ			valid, err := store.ValidateKey(r.Context(), rawKey)
    27Ôćĺ			if err != nil || !valid {
    28Ôćĺ				RespondError(w, r, http.StatusUnauthorized, "unauthorized", "Invalid API key")
    29Ôćĺ				return
    30Ôćĺ			}
    31Ôćĺ			go store.TouchKeyUsage(context.Background(), rawKey)
    32Ôćĺ			next.ServeHTTP(w, r)
    33Ôćĺ		})
    34Ôćĺ	}
    35Ôćĺ}
