    37Ôćĺfunc RateLimit(rps float64, burst int) Middleware {
    38Ôćĺ	var mu sync.Mutex
    39Ôćĺ	limiters := make(map[string]*rate.Limiter)
    40Ôćĺ	getLimiter := func(key string) *rate.Limiter {
    41Ôćĺ		mu.Lock()
    42Ôćĺ		defer mu.Unlock()
    43Ôćĺ		if lim, ok := limiters[key]; ok {
    44Ôćĺ			return lim
    45Ôćĺ		}
    46Ôćĺ		lim := rate.NewLimiter(rate.Limit(rps), burst)
    47Ôćĺ		limiters[key] = lim
    48Ôćĺ		return lim
    49Ôćĺ	}
    50Ôćĺ	return func(next http.Handler) http.Handler {
    51Ôćĺ		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    52Ôćĺ			key := r.RemoteAddr
    53Ôćĺ			if auth := r.Header.Get("Authorization"); strings.HasPrefix(auth, "Bearer ") {
    54Ôćĺ				key = strings.TrimPrefix(auth, "Bearer ")
    55Ôćĺ			}
    56Ôćĺ			lim := getLimiter(key)
    57Ôćĺ			if !lim.Allow() {
    58Ôćĺ				w.Header().Set("Retry-After", "1")
    59Ôćĺ				RespondError(w, r, http.StatusTooManyRequests, "rate_limited", "Too many requests")
    60Ôćĺ				return
    61Ôćĺ			}
    62Ôćĺ			next.ServeHTTP(w, r)
    63Ôćĺ		})
    64Ôćĺ	}
    65Ôćĺ}
