    10Ôćĺ
    11Ôćĺtype Middleware func(http.Handler) http.Handler
    12Ôćĺ
    13Ôćĺfunc Chain(mws ...Middleware) Middleware {
    14Ôćĺ	return func(final http.Handler) http.Handler {
    15Ôćĺ		for i := len(mws) - 1; i >= 0; i-- {
    16Ôćĺ			final = mws[i](final)
    17Ôćĺ		}
    18Ôćĺ		return final
    19Ôćĺ	}
    20Ôćĺ}
    21Ôćĺ
    22Ôćĺfunc RequestID(next http.Handler) http.Handler {
    23Ôćĺ	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    24Ôćĺ		id := uuid.New().String()
    25Ôćĺ		w.Header().Set("X-Request-ID", id)
    26Ôćĺ		next.ServeHTTP(w, r.WithContext(withRequestID(r.Context(), id)))
    27Ôćĺ	})
    28Ôćĺ}
