    30Ôćĺfunc Logger(next http.Handler) http.Handler {
    31Ôćĺ	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    32Ôćĺ		start := time.Now()
    33Ôćĺ		sw := &statusWriter{ResponseWriter: w, status: http.StatusOK}
    34Ôćĺ		next.ServeHTTP(sw, r)
    35Ôćĺ		slog.Info("request",
    36Ôćĺ			"request_id", getRequestID(r.Context()),
    37Ôćĺ			"method", r.Method,
    38Ôćĺ			"path", r.URL.Path,
    39Ôćĺ			"status", sw.status,
    40Ôćĺ			"duration_ms", time.Since(start).Milliseconds(),
    41Ôćĺ		)
    42Ôćĺ	})
    43Ôćĺ}
    44Ôćĺ
    45Ôćĺtype statusWriter struct {
    46Ôćĺ	http.ResponseWriter
    47Ôćĺ	status int
    48Ôćĺ}
    49Ôćĺ
    50Ôćĺfunc (w *statusWriter) WriteHeader(code int) {
