    31Ôćĺ			continue
    32Ôćĺ		}
    33Ôćĺ		match := true
    34Ôćĺ		for i, seg := range route.segments {
    35Ôćĺ			if seg != "*" && seg != parts[i] {
    36Ôćĺ				match = false
    37Ôćĺ				break
    38Ôćĺ			}
    39Ôćĺ		}
    40Ôćĺ		if match {
