   558Ôćĺ   558Ôćĺ// StateStore holds OAuth state parameters in memory with TTL and size limit.
   559Ôćĺ   559Ôćĺtype StateStore struct {
   560Ôćĺ   560Ôćĺ	mu      sync.Mutex
   561Ôćĺ   561Ôćĺ	entries map[string]stateEntry
   562Ôćĺ   562Ôćĺ	maxSize int
   563Ôćĺ   563Ôćĺ	ttl     time.Duration
   564Ôćĺ   564Ôćĺ}
   565Ôćĺ   565Ôćĺ
   566Ôćĺ   566Ôćĺ// NewStateStore creates a state store with the given max size and TTL per entry.
   567Ôćĺ   567Ôćĺfunc NewStateStore(maxSize int, ttl time.Duration) *StateStore {
   568Ôćĺ   568Ôćĺ	return &StateStore{
   569Ôćĺ   569Ôćĺ		entries: make(map[string]stateEntry),
   570Ôćĺ   570Ôćĺ		maxSize: maxSize,
   571Ôćĺ   571Ôćĺ		ttl:     ttl,
   572Ôćĺ   572Ôćĺ	}
   573Ôćĺ   573Ôćĺ}
   574Ôćĺ   574Ôćĺ
   575Ôćĺ   575Ôćĺ// Create generates a random state string and stores it. Returns "" if the store is full.
   576Ôćĺ   576Ôćĺfunc (s *StateStore) Create() string {
   577Ôćĺ   577Ôćĺ	s.mu.Lock()
   578Ôćĺ   578Ôćĺ	defer s.mu.Unlock()
   579Ôćĺ   579Ôćĺ
   580Ôćĺ   580Ôćĺ	// Sweep expired before checking size
   581Ôćĺ   581Ôćĺ	now := time.Now()
   582Ôćĺ   582Ôćĺ	for k, v := range s.entries {
   583Ôćĺ   583Ôćĺ		if now.After(v.expiresAt) {
   584Ôćĺ   584Ôćĺ			delete(s.entries, k)
   585Ôćĺ   585Ôćĺ		}
   586Ôćĺ   586Ôćĺ	}
   587Ôćĺ   587Ôćĺ
   588Ôćĺ   588Ôćĺ	if len(s.entries) >= s.maxSize {
   589Ôćĺ   589Ôćĺ		return ""
   590Ôćĺ   590Ôćĺ	}
   591Ôćĺ   591Ôćĺ
   592Ôćĺ   592Ôćĺ	b := make([]byte, 16)
   593Ôćĺ   593Ôćĺ	if _, err := rand.Read(b); err != nil {
   594Ôćĺ   594Ôćĺ		return ""
   595Ôćĺ   595Ôćĺ	}
   596Ôćĺ   596Ôćĺ	state := hex.EncodeToString(b)
   597Ôćĺ   597Ôćĺ	s.entries[state] = stateEntry{expiresAt: now.Add(s.ttl)}
   598Ôćĺ   598Ôćĺ	return state
   599Ôćĺ   599Ôćĺ}

