    10Ôćĺ// dynamicRoutes maps URL path patterns to their static export HTML files.
    11Ôćĺ// Next.js static export generates these with placeholder param "0".
    12Ôćĺ// The order matters: more specific patterns must come first.
    13Ôćĺvar dynamicRoutes = []struct {
    14Ôćĺ	// segments is the split URL pattern where "*" matches any single segment.
    15Ôćĺ	segments []string
    16Ôćĺ	// file is the path to the pre-rendered HTML relative to webDir.
    17Ôćĺ	file string
    18Ôćĺ}{
    19Ôćĺ	{[]string{"projects", "*", "semantic-releases", "*"}, "projects/0/semantic-releases/0.html"},
    20Ôćĺ	{[]string{"projects", "*", "agent"}, "projects/0/agent.html"},
    21Ôćĺ	{[]string{"projects", "*"}, "projects/0.html"},
    22Ôćĺ	{[]string{"releases", "*"}, "releases/0.html"},
    23Ôćĺ}
    24Ôćĺ
    25Ôćĺ// matchDynamicRoute checks if the URL path matches a dynamic route pattern
    26Ôćĺ// and returns the corresponding HTML file path, or empty string if no match.
    27Ôćĺfunc matchDynamicRoute(urlPath string) string {
    28Ôćĺ	parts := strings.Split(strings.Trim(urlPath, "/"), "/")
    29Ôćĺ	for _, route := range dynamicRoutes {
    30Ôćĺ		if len(parts) != len(route.segments) {
    31Ôćĺ			continue
    32Ôćĺ		}
    33Ôćĺ		match := true
    34Ôćĺ		for i, seg := range route.segments {
    35Ôćĺ			if seg != "*" && seg != parts[i] {
    36Ôćĺ				match = false
    37Ôćĺ				break
    38Ôćĺ			}
    39Ôćĺ		}
    40Ôćĺ		if match {
    41Ôćĺ			return route.file
    42Ôćĺ		}
    43Ôćĺ	}
    44Ôćĺ	return ""
    45Ôćĺ}
    46Ôćĺ
    47Ôćĺ// RegisterFrontend serves the Next.js static export from webDir.
    48Ôćĺ// It handles dynamic routes by mapping them to their pre-rendered HTML shells,
    49Ôćĺ// which then fetch real data client-side via SWR.
    50Ôćĺfunc RegisterFrontend(mux *http.ServeMux, webDir string) {
    51Ôćĺ	mux.Handle("GET /", http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    52Ôćĺ		// Try the exact path first (static assets like JS, CSS, images)
    53Ôćĺ		path := filepath.Join(webDir, filepath.Clean(r.URL.Path))
    54Ôćĺ		if info, err := os.Stat(path); err == nil && !info.IsDir() {
    55Ôćĺ			http.ServeFile(w, r, path)
    56Ôćĺ			return
    57Ôćĺ		}
    58Ôćĺ		// Try path + ".html" (Next.js static export convention for static pages)
    59Ôćĺ		if info, err := os.Stat(path + ".html"); err == nil && !info.IsDir() {
    60Ôćĺ			http.ServeFile(w, r, path+".html")
    61Ôćĺ			return
    62Ôćĺ		}
    63Ôćĺ		// Try dynamic route patterns (e.g. /projects/{id} Ôćĺ projects/0.html)
    64Ôćĺ		if file := matchDynamicRoute(r.URL.Path); file != "" {
    65Ôćĺ			http.ServeFile(w, r, filepath.Join(webDir, file))
    66Ôćĺ			return
    67Ôćĺ		}
    68Ôćĺ		// Fall back to index.html for unmatched routes
    69Ôćĺ		http.ServeFile(w, r, filepath.Join(webDir, "index.html"))
    70Ôćĺ	}))
    71Ôćĺ}
